package problems;

public class TrappingRainWater {

    public static void main(String[] args) {
        int[] height = {0, 1, 0, 2, 1, 0, 1, 3, 2, 1, 2, 1};
        System.out.println("Max water which can be trapped: " + trapWater(height));
    }

    /**
     * Two-pointer approach to calculate trapped rain water.
     * 
     * Time: O(n), Space: O(1)
     * 
     * Algorithm:
     * - Use two pointers (left and right) starting from both ends
     * - Track maximum heights seen from left and right
     * - Water at position = min(leftMax, rightMax) - height[i]
     * - Move pointer with smaller height (potential for more water)
     * 
     * Key insight: Water level at any position is determined by the
     * minimum of (max height on left, max height on right).
     */
    public static int trapWater(int[] height) {
        if (height == null || height.length < 3) {
            return 0;
        }

        int left = 0;
        int right = height.length - 1;
        int total = 0;

        int leftMax = height[left];
        int rightMax = height[right];

        while (left < right) {
            if (height[left] < height[right]) {
                // Process left side
                leftMax = Math.max(leftMax, height[left]);

                int heightDiff = leftMax - height[left];
                if (heightDiff > 0) {
                    total += heightDiff;
                }
                left++;
            } else {
                // Process right side
                rightMax = Math.max(rightMax, height[right]);

                int heightDiff = rightMax - height[right];
                if (heightDiff > 0) {
                    total += heightDiff;
                }
                right--;
            }
        }

        return total;
    }
}

// Example 1:
// Input: height = [0,1,0,2,1,0,1,3,2,1,2,1]
// Output: 6
// Explanation: 6 units of rain water are trapped

// Example 2:
// Input: height = [4,2,0,3,2,5]
// Output: 9

// Time Complexity: O(n) - single pass with two pointers
// Space Complexity: O(1) - only using constant extra space
